    if (Number(execution?.videoProgressForwardIntervalSec) > 0) parts.push(`ProgressInterval=${Number(execution.videoProgressForwardIntervalSec)}s`);
    const sessionKey = String(execution?.progressForwardSessionKey || "").trim();
