function renderFaviconResponse(method = "GET") {
  const headers = new Headers({
    "Content-Type": "image/svg+xml;charset=UTF-8",
    "Cache-Control": "public, max-age=86400, s-maxage=604800, immutable"
  });
  applySecurityHeaders(headers);
  return new Response(method === "HEAD" ? null : SITE_FAVICON_SVG, { headers });
}

const ADMIN_HTML_DYNAMIC_PLACEHOLDERS = Object.freeze([
  "__ADMIN_BOOTSTRAP_JSON__",
  "__INIT_HEALTH_BANNER__",
  "__ADMIN_APP_ROOT__"
]);
const ADMIN_HTML_VARIANT_ETAG = "embedded-fallback-v1";
const ADMIN_HTML_PARTS_PLAIN = splitAdminHtmlTemplate(ADMIN_FALLBACK_HTML_TEMPLATE);
const ADMIN_EMBEDDED_TEMPLATE_MODE = "minimal-split-parts";
const ADMIN_FINAL_UI_HTML_RETIRED = true;

function splitAdminHtmlTemplate(template = "") {
  const source = String(template || "");
  const parts = [];
  let cursor = 0;
  for (const placeholder of ADMIN_HTML_DYNAMIC_PLACEHOLDERS) {
    const index = source.indexOf(placeholder, cursor);
    if (index < 0) throw new Error(`missing admin html placeholder: ${placeholder}`);
    parts.push(source.slice(cursor, index));
    cursor = index + placeholder.length;
  }
  parts.push(source.slice(cursor));
  return parts;
}

function renderAdminHtmlTemplate(parts = [], replacements = {}) {
  let html = String(parts[0] || "");
  for (let index = 0; index < ADMIN_HTML_DYNAMIC_PLACEHOLDERS.length; index += 1) {
    const placeholder = ADMIN_HTML_DYNAMIC_PLACEHOLDERS[index];
    html += String(replacements[placeholder] || "");
    html += String(parts[index + 1] || "");
  }
  return html;
}

const ADMIN_BOOTSTRAP_PLACEHOLDER = "__ADMIN_BOOTSTRAP_JSON__";
const ADMIN_INIT_HEALTH_BANNER_PLACEHOLDER = "__INIT_HEALTH_BANNER__";
const ADMIN_APP_ROOT_PLACEHOLDER = "__ADMIN_APP_ROOT__";
const ADMIN_APP_ROOT_HTML = "";
const ADMIN_HTML_CACHE_CONTROL = "public, max-age=300, s-maxage=600";
const ADMIN_HTML_CACHE_KEY_ORIGIN = "https://admin-shell-cache.invalid";
const ADMIN_REMOTE_SHELL_BROWSER_CACHE_CONTROL = "public, max-age=0, must-revalidate";
const ADMIN_REMOTE_SHELL_EDGE_CACHE_CONTROL = "public, max-age=31536000, immutable";
const ADMIN_REMOTE_SHELL_REVALIDATE_MS = 5 * 60 * 1000;
const ADMIN_REMOTE_SHELL_MAX_BYTES = 2 * 1024 * 1024;
const ADMIN_REMOTE_SHELL_CACHED_AT_HEADER = "X-Admin-Shell-Cached-At";
const ADMIN_REMOTE_SHELL_SOURCE_ETAG_HEADER = "X-Admin-Shell-Source-Etag";
const ADMIN_REMOTE_SHELL_SOURCE_LAST_MODIFIED_HEADER = "X-Admin-Shell-Source-Last-Modified";
const ADMIN_REMOTE_SHELL_SOURCE_HASH_HEADER = "X-Admin-Shell-Source-Hash";

function buildAdminBootstrapPayload(env, initHealth = buildInitHealth(env)) {
  const adminPath = getAdminPath(env);
  return {
    adminPath,
    loginPath: getAdminLoginPath(env),
    initHealth,
    hostDomain: resolveConfiguredHost(env),
    shell: buildAdminShellState(env, initHealth)
  };
}

function measureAdminShellTemplateBytes() {
  if (cachedAdminTemplateBytes >= 0) return cachedAdminTemplateBytes;
  if (!Array.isArray(ADMIN_HTML_PARTS_PLAIN) || ADMIN_HTML_PARTS_PLAIN.length !== ADMIN_HTML_DYNAMIC_PLACEHOLDERS.length + 1) {
    cachedAdminTemplateBytes = 0;
    return 0;
  }
  const encoder = new TextEncoder();
  let totalBytes = 0;
  for (let index = 0; index < ADMIN_HTML_PARTS_PLAIN.length; index += 1) {
    totalBytes += encoder.encode(String(ADMIN_HTML_PARTS_PLAIN[index] || "")).length;
    if (index < ADMIN_HTML_DYNAMIC_PLACEHOLDERS.length) {
      totalBytes += encoder.encode(ADMIN_HTML_DYNAMIC_PLACEHOLDERS[index]).length;
    }
  }
  cachedAdminTemplateBytes = totalBytes;
  return cachedAdminTemplateBytes;
}

function buildAdminShellLifecycleState(remoteShellConfigured = false, healthyShell = false) {
  if (remoteShellConfigured && healthyShell) return "remote_ready";
  if (remoteShellConfigured) return "remote_blocked_by_init_health";
  return "embedded_only";
}

function buildAdminShellRetirementState(embeddedFallbackAvailable = false, finalUiHtmlRetired = ADMIN_FINAL_UI_HTML_RETIRED) {
  if (!embeddedFallbackAvailable) return "embedded_fallback_missing";
  return finalUiHtmlRetired ? "embedded_fallback_retained" : "legacy_inline_shell_active";
}

function buildAdminShellEffectiveMode(mode = "embedded", routeState = "") {
  if (String(mode || "").trim().toLowerCase() === "remote") return "remote_shell";
  return String(routeState || "").trim() === "embedded_fallback"
    ? "embedded_fallback"
    : "embedded_shell";
}

function buildAdminEmbeddedFallbackRuntimeState(embeddedFallbackAvailable = false, routeState = "") {
  if (!embeddedFallbackAvailable) return "missing";
  return String(routeState || "").trim() === "embedded_fallback"
    ? "active"
    : "retained";
}

function buildAdminShellState(env, initHealth = buildInitHealth(env)) {
  const remoteShellIndexUrl = resolveAdminShellIndexUrl(env);
  const healthyShell = initHealth?.ok === true;
  const embeddedTemplateBytes = measureAdminShellTemplateBytes();
  const remoteShellConfigured = Boolean(remoteShellIndexUrl);
  const embeddedFallbackAvailable = embeddedTemplateBytes > 0;
  let remoteShellOrigin = "";
  if (remoteShellIndexUrl) {
    try {
      remoteShellOrigin = new URL(remoteShellIndexUrl).origin;
    } catch {
      remoteShellOrigin = "";
    }
  }

  return {
    mode: remoteShellConfigured && healthyShell ? "remote-preferred" : "embedded",
    lifecycleState: buildAdminShellLifecycleState(remoteShellConfigured, healthyShell),
    embeddedFallbackState: embeddedFallbackAvailable ? "retained" : "missing",
    retirementState: buildAdminShellRetirementState(embeddedFallbackAvailable),
    remoteShellConfigured,
    remoteShellIndexUrl,
    remoteShellOrigin,
    initHealthOk: healthyShell,
    embeddedFallbackAvailable,
    embeddedTemplateSource: ADMIN_EMBEDDED_TEMPLATE_MODE,
    embeddedTemplateMode: ADMIN_EMBEDDED_TEMPLATE_MODE,
    embeddedTemplateBytes,
    finalUiHtmlRetired: ADMIN_FINAL_UI_HTML_RETIRED
  };
}

function resolveAdminShellIndexUrl(env) {
  const rawUrl = String(env?.ADMIN_SHELL_INDEX_URL || "").trim();
  if (!rawUrl) return "";
  try {
    const parsedUrl = new URL(rawUrl);
    if (!["http:", "https:"].includes(parsedUrl.protocol)) return "";
    return parsedUrl.toString();
  } catch {
    return "";
  }
}

function normalizeAdminShellRuntimeStatus(options = {}) {
  const shellState = isPlainObject(options.shellState) ? options.shellState : {};
  const initHealth = isPlainObject(options.initHealth) ? options.initHealth : {};
  const configuredRemoteIndexUrl = String(options.remoteShellIndexUrl || shellState.remoteShellIndexUrl || "").trim();
  const mode = String(options.mode || "").trim().toLowerCase() === "remote" ? "remote" : "embedded";
  const remoteShellConfigured = shellState.remoteShellConfigured === true || Boolean(configuredRemoteIndexUrl);
  const embeddedFallbackAvailable = shellState.embeddedFallbackAvailable === true;
  const finalUiHtmlRetired = shellState.finalUiHtmlRetired !== false;
  const routeState = String(options.routeState || "").trim() || (mode === "remote" ? "remote_active" : "embedded_active");
  const lifecycleState = String(options.lifecycleState || shellState.lifecycleState || "").trim()
    || buildAdminShellLifecycleState(remoteShellConfigured, mode === "remote");
  const embeddedFallbackState = String(options.embeddedFallbackState || shellState.embeddedFallbackState || "").trim()
    || buildAdminEmbeddedFallbackRuntimeState(embeddedFallbackAvailable, routeState);
  const retirementState = String(options.retirementState || shellState.retirementState || "").trim()
    || buildAdminShellRetirementState(embeddedFallbackAvailable, finalUiHtmlRetired);
  return {
    ...shellState,
    mode,
    effectiveMode: buildAdminShellEffectiveMode(mode, routeState),
    lifecycleState,
    embeddedFallbackState,
    retirementState,
    sourceType: String(options.sourceType || "").trim().toLowerCase() || (mode === "remote" ? "remote_fetch" : "embedded_local"),
    routeState,
    remoteShellIndexUrl: configuredRemoteIndexUrl,
    remoteShellOrigin: String(shellState.remoteShellOrigin || "").trim(),
    remoteCacheState: String(options.remoteCacheState || "").trim().toLowerCase(),
    revalidateDue: options.revalidateDue === true,
    lastFetchStatus: String(options.lastFetchStatus || "").trim().toLowerCase(),
    reason: String(options.reason || "").trim(),
    requestPath: String(options.requestPath || "").trim(),
    initHealthOk: initHealth.ok === true,
    initHealthMissing: [...new Set((Array.isArray(initHealth.missing) ? initHealth.missing : [])
      .map(item => String(item || "").trim())
      .filter(Boolean))],
    fallbackRetained: embeddedFallbackAvailable,
    templateMode: String(shellState.embeddedTemplateMode || shellState.embeddedTemplateSource || "").trim() || ADMIN_EMBEDDED_TEMPLATE_MODE,
    finalUiHtmlRetired,
    updatedAt: String(options.updatedAt || "").trim() || new Date().toISOString()
  };
}

async function patchAdminShellRuntimeStatus(envOrStore, options = {}, ctx = null) {
  const shellState = isPlainObject(options.shellState) ? options.shellState : buildAdminShellState(envOrStore, options.initHealth);
  const statusPatch = normalizeAdminShellRuntimeStatus({
    ...options,
    shellState
  });
  return withNonCriticalFallback(
    Database.patchOpsStatus(envOrStore, { adminShell: statusPatch }, ctx),
    "admin.shell_status_patch",
    {
      requestPath: statusPatch.requestPath,
      mode: statusPatch.mode,
      sourceType: statusPatch.sourceType
    },
    null
  );
}

function describeAdminEmbeddedFallbackReason(reason = "", initHealthOk = false) {
  const normalizedReason = String(reason || "").trim();
  if (!normalizedReason) {
    return initHealthOk
      ? "当前请求仍由 embedded fallback 返回，通常是因为 remote shell 还没有配置完成。"
      : "当前请求仍由 embedded fallback 返回，因为初始化健康检查还没有通过。";
  }
  if (normalizedReason === "remote_shell_not_configured") {
    return "ADMIN_SHELL_INDEX_URL 尚未配置，Worker 还不能把 /admin 默认切到远端 index.html。";
  }
  if (normalizedReason === "init_health_blocked_remote_shell") {
    return "初始化健康检查未通过，Worker 暂时不会让 /admin 进入 remote shell。";
  }
  if (normalizedReason.startsWith("remote_shell_render_failed")) {
    const detail = normalizedReason.replace(/^remote_shell_render_failed:\s*/i, "").trim();
    return detail
      ? `Worker 拉取远端 index.html 失败，当前请求已回退到 embedded fallback：${detail}`
      : "Worker 拉取远端 index.html 失败，当前请求已回退到 embedded fallback。";
  }
  return normalizedReason;
}

function buildAdminFallbackActionLink(href = "", label = "", tone = "secondary", newTab = false) {
  const normalizedHref = String(href || "").trim();
  const normalizedLabel = String(label || "").trim();
  if (!normalizedHref || !normalizedLabel) return "";
  const buttonToneClass = tone === "primary" ? "admin-fallback-btn-primary" : "admin-fallback-btn-secondary";
  const targetAttributes = newTab ? ' target="_blank" rel="noopener noreferrer"' : "";
  return `<a href="${escapeHtml(normalizedHref)}" class="admin-fallback-btn ${buttonToneClass}"${targetAttributes}>${escapeHtml(normalizedLabel)}</a>`;
}

function buildAdminFallbackStatCard(label = "", value = "") {
  return `<article class="admin-fallback-stat"><div class="admin-fallback-k">${escapeHtml(label)}</div><div class="admin-fallback-v">${escapeHtml(value)}</div></article>`;
}

function buildEmbeddedAdminFallbackContent(bootstrap = {}, shellState = {}, initHealth = {}, statusOptions = {}) {
  const adminPath = String(bootstrap.adminPath || "/admin").trim() || "/admin";
  const loginPath = String(bootstrap.loginPath || "").trim();
  const remoteShellIndexUrl = String(statusOptions.remoteShellIndexUrl || shellState.remoteShellIndexUrl || "").trim();
  const lifecycleState = String(shellState.lifecycleState || "").trim() || "embedded_only";
  const initHealthMissing = [...new Set((Array.isArray(initHealth.missing) ? initHealth.missing : [])
    .map(item => String(item || "").trim())
    .filter(Boolean))];
  const initHealthSummary = initHealth.ok === true
    ? "已通过，remote shell 可以成为默认返回路径"
    : (initHealthMissing.length ? `缺失项：${initHealthMissing.join(" / ")}` : "未通过");
  const runtimeSummary = String(statusOptions.routeState || "").trim() === "embedded_fallback"
    ? "当前请求已落回 embedded fallback"
    : "当前仍由 embedded fallback 直接返回";
  const reasonSummary = describeAdminEmbeddedFallbackReason(statusOptions.reason || "", initHealth.ok === true);
  const fallbackSummary = `${Number(shellState.embeddedTemplateBytes) || 0} bytes / ${String(shellState.embeddedTemplateSource || ADMIN_EMBEDDED_TEMPLATE_MODE || "unknown")}`;
  const actionLinks = [
    buildAdminFallbackActionLink(adminPath, "刷新 /admin", "primary"),
    loginPath ? buildAdminFallbackActionLink(loginPath, "打开登录页") : "",
    remoteShellIndexUrl ? buildAdminFallbackActionLink(remoteShellIndexUrl, "打开远端 index.html", "secondary", true) : ""
  ].filter(Boolean).join("");
  const debugPayload = {
    adminPath,
    loginPath,
    hostDomain: String(bootstrap.hostDomain || "").trim(),
    initHealth: {
      ok: initHealth.ok === true,
      missing: initHealthMissing
    },
    shell: {
      mode: String(shellState.mode || "").trim(),
      lifecycleState,
      retirementState: String(shellState.retirementState || "").trim(),
      remoteShellIndexUrl,
      embeddedTemplateSource: String(shellState.embeddedTemplateSource || "").trim(),
      embeddedTemplateBytes: Number(shellState.embeddedTemplateBytes) || 0,
      finalUiHtmlRetired: shellState.finalUiHtmlRetired === true
    },
    runtime: {
      routeState: String(statusOptions.routeState || "").trim(),
      sourceType: String(statusOptions.sourceType || "embedded_local").trim(),
      reason: String(statusOptions.reason || "").trim()
    }
  };

  return `<div class="admin-fallback-grid">${[
    buildAdminFallbackStatCard("当前状态", runtimeSummary),
    buildAdminFallbackStatCard("Fallback 原因", reasonSummary),
    buildAdminFallbackStatCard("Remote Shell", remoteShellIndexUrl || "ADMIN_SHELL_INDEX_URL 尚未配置"),
    buildAdminFallbackStatCard("Init Health", initHealthSummary),
    buildAdminFallbackStatCard("Lifecycle", lifecycleState),
    buildAdminFallbackStatCard("Embedded Fallback", fallbackSummary)
  ].join("")}</div><div class="admin-fallback-actions">${actionLinks}</div><section class="admin-fallback-panel"><h2>当前说明</h2><p>POST /admin API、日志、KV / D1、代理与鉴权语义保持不变；这次只把 Worker 里的整套旧前端物理下线，保留一个更小的只读兜底壳。</p><p class="admin-fallback-note">如果 remote shell 已配置但仍频繁回退，请优先检查远端 index.html 可访问性、内容合法性和缓存刷新状态。</p><details><summary>查看当前 fallback 快照</summary><pre>${escapeHtml(JSON.stringify(debugPayload, null, 2))}</pre></details></section>`;
}

function renderAdminHtmlShell(bootstrapJson = "{}", initHealthBannerHtml = "", appRootHtml = ADMIN_APP_ROOT_HTML) {
  if (!Array.isArray(ADMIN_HTML_PARTS_PLAIN) || ADMIN_HTML_PARTS_PLAIN.length !== ADMIN_HTML_DYNAMIC_PLACEHOLDERS.length + 1) {
    return "";
  }
  return renderAdminHtmlTemplate(
    ADMIN_HTML_PARTS_PLAIN,
    {
      [ADMIN_BOOTSTRAP_PLACEHOLDER]: String(bootstrapJson || "{}"),
      [ADMIN_INIT_HEALTH_BANNER_PLACEHOLDER]: String(initHealthBannerHtml || ""),
      [ADMIN_APP_ROOT_PLACEHOLDER]: String(appRootHtml || ADMIN_APP_ROOT_HTML)
    }
  );
}

function buildAdminHtmlVariantEtag(bootstrap = {}, initHealth = null, appRootHtml = ADMIN_APP_ROOT_HTML) {
  const normalizedBootstrap = isPlainObject(bootstrap) ? bootstrap : {};
  const normalizedInitHealth = isPlainObject(initHealth)
    ? initHealth
    : (isPlainObject(normalizedBootstrap.initHealth) ? normalizedBootstrap.initHealth : {});
  const variantSignature = {
    templateRevision: String(ADMIN_HTML_VARIANT_ETAG || "").trim() || "admin-shell",
    adminPath: String(normalizedBootstrap.adminPath || "").trim(),
    loginPath: String(normalizedBootstrap.loginPath || "").trim(),
    hostDomain: normalizeHostnameText(normalizedBootstrap.hostDomain),
    initHealthOk: normalizedInitHealth.ok === true,
    initHealthMissing: [...new Set((Array.isArray(normalizedInitHealth.missing) ? normalizedInitHealth.missing : [])
      .map(item => String(item || "").trim())
      .filter(Boolean))],
    appRootHash: hashStableText(String(appRootHtml || ADMIN_APP_ROOT_HTML))
  };
  return `${variantSignature.templateRevision}-${hashStableText(serializeConfigValue(variantSignature))}`;
}

function formatAdminHtmlEtag(etag = "") {
  return `"${String(etag || "").trim()}"`;
}

function normalizeEtagToken(value = "") {
  return String(value || "").trim().replace(/^W\//i, "").replace(/^"(.*)"$/, "$1");
}

function requestHasMatchingEtag(request, currentEtag = "") {
  const ifNoneMatch = String(request?.headers?.get?.("If-None-Match") || "").trim();
  const normalizedCurrentEtag = normalizeEtagToken(currentEtag);
  if (!ifNoneMatch || !normalizedCurrentEtag) return false;
  return ifNoneMatch.split(",").some((token) => {
    const normalizedToken = normalizeEtagToken(token);
    return normalizedToken === "*" || normalizedToken === normalizedCurrentEtag;
  });
}

function buildAdminHtmlCacheKeyRequest(request, variantEtag = "") {
  const requestUrl = request instanceof Request ? new URL(request.url) : new URL(String(request || ""), ADMIN_HTML_CACHE_KEY_ORIGIN);
  const cacheUrl = new URL(requestUrl.pathname, ADMIN_HTML_CACHE_KEY_ORIGIN);
  cacheUrl.searchParams.set("variant", String(variantEtag || ""));
  return new Request(cacheUrl.toString(), { method: "GET" });
}

function buildAdminRemoteShellCacheKeyRequest(request, remoteShellIndexUrl = "") {
  const requestUrl = request instanceof Request ? new URL(request.url) : new URL(String(request || ""), ADMIN_HTML_CACHE_KEY_ORIGIN);
  const cacheUrl = new URL(requestUrl.pathname, ADMIN_HTML_CACHE_KEY_ORIGIN);
  cacheUrl.searchParams.set("remote", hashStableText(String(remoteShellIndexUrl || "").trim()));
  return new Request(cacheUrl.toString(), { method: "GET" });
}

function buildAdminHtmlResponseHeaders(etag = "", cacheControl = "no-store, max-age=0") {
  const headers = new Headers({
    "Content-Type": "text/html;charset=UTF-8",
    "Cache-Control": String(cacheControl || "no-store, max-age=0")
  });
  applySecurityHeaders(headers);
  if (etag) headers.set("ETag", formatAdminHtmlEtag(etag));
  return headers;
}

function buildAdminNotModifiedResponse(etag = "", cacheControl = ADMIN_HTML_CACHE_CONTROL) {
  const headers = buildAdminHtmlResponseHeaders(etag, cacheControl);
  headers.delete("Content-Type");
  return new Response(null, { status: 304, headers });
}

function buildAdminHeadResponseFrom(response) {
  if (!response) return new Response(null, { status: 500 });
  return new Response(null, {
    status: response.status,
    statusText: response.statusText,
    headers: new Headers(response.headers)
  });
}

function normalizeAdminHttpDateHeader(value = "") {
  const rawValue = String(value || "").trim();
  if (!rawValue) return "";
  const timestamp = Date.parse(rawValue);
  return Number.isFinite(timestamp) ? new Date(timestamp).toUTCString() : "";
}

function requestHasMatchingLastModified(request, currentLastModified = "") {
  const ifModifiedSince = String(request?.headers?.get?.("If-Modified-Since") || "").trim();
  const normalizedCurrentLastModified = normalizeAdminHttpDateHeader(currentLastModified);
  if (!ifModifiedSince || !normalizedCurrentLastModified) return false;
  const requestTimestamp = Date.parse(ifModifiedSince);
  const currentTimestamp = Date.parse(normalizedCurrentLastModified);
  if (!Number.isFinite(requestTimestamp) || !Number.isFinite(currentTimestamp)) return false;
  return requestTimestamp >= currentTimestamp;
}

function requestMatchesAdminHtmlResponse(request, response) {
  const ifNoneMatch = String(request?.headers?.get?.("If-None-Match") || "").trim();
  if (ifNoneMatch) {
    return requestHasMatchingEtag(request, response?.headers?.get?.("ETag") || "");
  }
  return requestHasMatchingLastModified(request, response?.headers?.get?.("Last-Modified") || "");
}

function buildAdminNotModifiedResponseFrom(response, cacheControl = ADMIN_HTML_CACHE_CONTROL) {
  const headers = buildAdminHtmlResponseHeaders(
    normalizeEtagToken(response?.headers?.get?.("ETag") || ""),
    cacheControl
  );
  const lastModified = normalizeAdminHttpDateHeader(response?.headers?.get?.("Last-Modified") || "");
  if (lastModified) headers.set("Last-Modified", lastModified);
  headers.delete("Content-Type");
  return new Response(null, { status: 304, headers });
}

function buildAdminRemoteBootstrapMarkup(bootstrapJson = "{}") {
  return `<script id="admin-bootstrap" type="application/json">${String(bootstrapJson || "{}")}</script><script id="admin-bootstrap-loader">try{window.__ADMIN_BOOTSTRAP__=JSON.parse(document.getElementById("admin-bootstrap")?.textContent||"{}")}catch(_){window.__ADMIN_BOOTSTRAP__=window.__ADMIN_BOOTSTRAP__||{},window.__ADMIN_UI_BOOT_ERROR__=window.__ADMIN_UI_BOOT_ERROR__||"admin bootstrap parse failed: "+(_?.message||String(_||"unknown_error"))}</script>`;
}

function injectMarkupIntoHtmlDocument(html = "", markup = "") {
  const sourceHtml = String(html || "");
  const injectedMarkup = String(markup || "");
  if (!sourceHtml || !injectedMarkup) return sourceHtml;
  const headCloseMatch = sourceHtml.match(/<\/head>/i);
  if (headCloseMatch && Number.isInteger(headCloseMatch.index) && headCloseMatch.index >= 0) {
    return `${sourceHtml.slice(0, headCloseMatch.index)}${injectedMarkup}${sourceHtml.slice(headCloseMatch.index)}`;
  }
  const bodyOpenMatch = sourceHtml.match(/<body[^>]*>/i);
  if (bodyOpenMatch && Number.isInteger(bodyOpenMatch.index) && bodyOpenMatch.index >= 0) {
    const insertIndex = bodyOpenMatch.index + bodyOpenMatch[0].length;
    return `${sourceHtml.slice(0, insertIndex)}${injectedMarkup}${sourceHtml.slice(insertIndex)}`;
  }
  return `${injectedMarkup}${sourceHtml}`;
}

function extractAdminRemoteShellAssetUrls(html = "", baseUrl = "") {
  const sourceHtml = String(html || "");
  if (!sourceHtml) return [];

  let resolvedBaseUrl = null;
  try {
    resolvedBaseUrl = new URL(String(baseUrl || "").trim());
  } catch {
    resolvedBaseUrl = null;
  }

  const assetUrls = [];
  const assetMatches = sourceHtml.matchAll(/\b(?:src|href)=["']([^"'#][^"']*)["']/gi);
  for (const match of assetMatches) {
    const rawAssetUrl = String(match?.[1] || "").trim();
    if (!rawAssetUrl || /^data:/i.test(rawAssetUrl) || /^javascript:/i.test(rawAssetUrl)) continue;
    if (!/\.(?:m?js|css)(?:[?#]|$)/i.test(rawAssetUrl)) continue;
    try {
      const normalizedAssetUrl = resolvedBaseUrl
        ? new URL(rawAssetUrl, resolvedBaseUrl).toString()
        : new URL(rawAssetUrl).toString();
      assetUrls.push(normalizedAssetUrl);
    } catch {
      continue;
    }
  }

  return [...new Set(assetUrls)];
}

function isMutableJsdelivrGithubAssetUrl(assetUrl = "") {
  let parsedUrl = null;
  try {
    parsedUrl = new URL(String(assetUrl || "").trim());
  } catch {
    return false;
  }
  if (!/(^|\.)jsdelivr\.net$/i.test(parsedUrl.hostname)) return false;

  const matchedRef = parsedUrl.pathname.match(/^\/gh\/[^/]+\/[^@/]+@([^/]+)\//i);
  if (!matchedRef) return false;

  const ref = decodeURIComponent(String(matchedRef[1] || "").trim());
  if (!ref) return false;
  if (/^[0-9a-f]{7,40}$/i.test(ref)) return false;
  if (/^v?\d+\.\d+\.\d+(?:[-+][0-9A-Za-z.-]+)?$/i.test(ref)) return false;
  return true;
}

function getAdminRemoteShellAssetPolicyViolations(html = "", baseUrl = "") {
  const assetUrls = extractAdminRemoteShellAssetUrls(html, baseUrl);
  const violations = [];

  for (const assetUrl of assetUrls) {
    if (/^https?:\/\/(?:[^/]+\.)?esm\.sh\//i.test(assetUrl)) {
      violations.push(`esm.sh 资产不再允许：${assetUrl}`);
      continue;
    }
    if (isMutableJsdelivrGithubAssetUrl(assetUrl)) {
      violations.push(`jsDelivr gh 可变 ref 不再允许：${assetUrl}`);
    }
  }

  return violations;
}

function hasAdminRemoteShellAppRoot(html = "") {
  return /\bid=(['"])app\1/i.test(String(html || ""));
}

function hasAdminRemoteShellHtmlDocument(html = "") {
  const normalizedHtml = String(html || "").trim();
  if (!normalizedHtml) return false;
  return /<!doctype\s+html\b/i.test(normalizedHtml) || /<html\b/i.test(normalizedHtml);
}

function buildAdminRemoteShellVariantEtag(options = {}) {
  const bootstrap = isPlainObject(options.bootstrap) ? options.bootstrap : {};
  const initHealth = isPlainObject(options.initHealth)
    ? options.initHealth
    : (isPlainObject(bootstrap.initHealth) ? bootstrap.initHealth : {});
  const remoteSignature = {
    templateRevision: "admin-remote-shell",
    sourceHash: hashStableText(String(options.sourceUrl || "").trim()),
    originEtag: normalizeEtagToken(options.originEtag || ""),
    originLastModified: normalizeAdminHttpDateHeader(options.originLastModified || ""),
    htmlHash: hashStableText(String(options.html || "")),
    variantSeed: buildAdminHtmlVariantEtag(bootstrap, initHealth, "remote-admin-shell")
  };
  return `admin-remote-shell-${hashStableText(serializeConfigValue(remoteSignature))}`;
}

function buildAdminRemoteShellStoredResponse(html = "", options = {}) {
  const headers = buildAdminHtmlResponseHeaders(options.variantEtag || "", ADMIN_REMOTE_SHELL_EDGE_CACHE_CONTROL);
  const lastModified = normalizeAdminHttpDateHeader(options.lastModified || "");
  if (lastModified) headers.set("Last-Modified", lastModified);
  headers.set(ADMIN_REMOTE_SHELL_CACHED_AT_HEADER, String(nowMs()));
  const originEtag = normalizeEtagToken(options.originEtag || "");
  if (originEtag) headers.set(ADMIN_REMOTE_SHELL_SOURCE_ETAG_HEADER, originEtag);
  const originLastModified = normalizeAdminHttpDateHeader(options.originLastModified || "");
  if (originLastModified) headers.set(ADMIN_REMOTE_SHELL_SOURCE_LAST_MODIFIED_HEADER, originLastModified);
  const sourceHash = hashStableText(String(options.sourceUrl || "").trim());
  if (sourceHash) headers.set(ADMIN_REMOTE_SHELL_SOURCE_HASH_HEADER, sourceHash);
  return new Response(String(html || ""), {
    status: 200,
    headers
  });
}

function buildAdminRemoteShellClientResponse(response, requestMethod = "GET") {
  if (!response) return new Response("Remote admin shell unavailable", { status: 502 });
  const headers = new Headers(response.headers || {});
  headers.set("Content-Type", "text/html;charset=UTF-8");
  headers.set("Cache-Control", ADMIN_REMOTE_SHELL_BROWSER_CACHE_CONTROL);
  headers.delete(ADMIN_REMOTE_SHELL_CACHED_AT_HEADER);
  headers.delete(ADMIN_REMOTE_SHELL_SOURCE_ETAG_HEADER);
  headers.delete(ADMIN_REMOTE_SHELL_SOURCE_LAST_MODIFIED_HEADER);
  headers.delete(ADMIN_REMOTE_SHELL_SOURCE_HASH_HEADER);
  applySecurityHeaders(headers);
  return new Response(
    requestMethod === "HEAD" ? null : response.body,
    {
      status: response.status,
      statusText: response.statusText,
      headers
    }
  );
}

function getAdminRemoteShellCachedAt(response) {
  const cachedAt = Number.parseInt(String(response?.headers?.get?.(ADMIN_REMOTE_SHELL_CACHED_AT_HEADER) || ""), 10);
  return Number.isFinite(cachedAt) && cachedAt > 0 ? cachedAt : 0;
}

function shouldRevalidateAdminRemoteShell(response) {
  const cachedAt = getAdminRemoteShellCachedAt(response);
  if (!cachedAt) return true;
  return nowMs() - cachedAt >= ADMIN_REMOTE_SHELL_REVALIDATE_MS;
}

async function fetchAdminRemoteShellStoredResponse(remoteShellIndexUrl, bootstrap, initHealth, previousResponse = null) {
  const requestHeaders = new Headers();
  const previousOriginEtag = normalizeEtagToken(previousResponse?.headers?.get?.(ADMIN_REMOTE_SHELL_SOURCE_ETAG_HEADER) || "");
  const previousOriginLastModified = normalizeAdminHttpDateHeader(previousResponse?.headers?.get?.(ADMIN_REMOTE_SHELL_SOURCE_LAST_MODIFIED_HEADER) || "");
  if (previousOriginEtag) requestHeaders.set("If-None-Match", previousOriginEtag);
  if (previousOriginLastModified) requestHeaders.set("If-Modified-Since", previousOriginLastModified);

  const remoteResponse = await fetch(remoteShellIndexUrl, {
    method: "GET",
    headers: requestHeaders
  });
  if (remoteResponse.status === 304 && previousResponse) {
    const previousHtml = await previousResponse.text();
    return buildAdminRemoteShellStoredResponse(previousHtml, {
      variantEtag: normalizeEtagToken(previousResponse.headers.get("ETag") || ""),
      lastModified: remoteResponse.headers.get("Last-Modified") || previousResponse.headers.get("Last-Modified") || "",
      originEtag: remoteResponse.headers.get("ETag") || previousOriginEtag,
      originLastModified: remoteResponse.headers.get("Last-Modified") || previousOriginLastModified,
      sourceUrl: remoteShellIndexUrl
    });
  }
  if (!remoteResponse.ok) {
    throw new Error(`remote admin shell fetch failed: HTTP ${remoteResponse.status}`);
  }

  const contentType = String(remoteResponse.headers.get("Content-Type") || "").trim().toLowerCase();
  const contentLength = Number.parseInt(String(remoteResponse.headers.get("Content-Length") || ""), 10);
  if (Number.isFinite(contentLength) && contentLength > ADMIN_REMOTE_SHELL_MAX_BYTES) {
    throw new Error(`remote admin shell too large: ${contentLength} bytes`);
  }

  const remoteHtml = await remoteResponse.text();
  const remoteHtmlSize = new TextEncoder().encode(remoteHtml).length;
  if (!remoteHtml || remoteHtmlSize > ADMIN_REMOTE_SHELL_MAX_BYTES) {
    throw new Error(`remote admin shell payload invalid: ${remoteHtmlSize} bytes`);
  }
  const htmlDocumentDetected = hasAdminRemoteShellHtmlDocument(remoteHtml);
  if (contentType && !contentType.includes("text/html") && !contentType.includes("application/xhtml+xml")) {
    const allowPlainTextHtmlDocument = contentType.startsWith("text/plain") && htmlDocumentDetected;
    if (!allowPlainTextHtmlDocument) {
      throw new Error(`remote admin shell content-type invalid: ${contentType}`);
    }
  }
  if (!htmlDocumentDetected) {
    throw new Error("remote admin shell payload invalid: html document expected");
  }
  if (!hasAdminRemoteShellAppRoot(remoteHtml)) {
    throw new Error("remote admin shell missing #app root");
  }

  const assetPolicyViolations = getAdminRemoteShellAssetPolicyViolations(remoteHtml, remoteShellIndexUrl);
  if (assetPolicyViolations.length > 0) {
    throw new Error(`remote admin shell asset policy invalid: ${assetPolicyViolations.slice(0, 3).join(" | ")}`);
  }

  const bootstrapJson = serializeInlineJson(bootstrap);
  const renderedHtml = injectMarkupIntoHtmlDocument(
    remoteHtml,
    buildAdminRemoteBootstrapMarkup(bootstrapJson)
  );
  const lastModified = normalizeAdminHttpDateHeader(remoteResponse.headers.get("Last-Modified") || "") || new Date().toUTCString();
  return buildAdminRemoteShellStoredResponse(renderedHtml, {
    variantEtag: buildAdminRemoteShellVariantEtag({
      html: renderedHtml,
      bootstrap,
      initHealth,
      sourceUrl: remoteShellIndexUrl,
      originEtag: remoteResponse.headers.get("ETag") || "",
      originLastModified: lastModified
    }),
    lastModified,
    originEtag: remoteResponse.headers.get("ETag") || "",
    originLastModified: lastModified,
    sourceUrl: remoteShellIndexUrl
  });
}

async function revalidateAdminRemoteShellCache(request, edgeCache, cacheKey, remoteShellIndexUrl, bootstrap, initHealth, cachedResponse) {
  if (!edgeCache || typeof edgeCache.put !== "function") return null;
  const storedResponse = await fetchAdminRemoteShellStoredResponse(
    remoteShellIndexUrl,
    bootstrap,
    initHealth,
    cachedResponse
  );
  await edgeCache.put(cacheKey, storedResponse.clone());
  return storedResponse;
}

async function renderEmbeddedAdminPage(request, env, ctx, initHealth = buildInitHealth(env), statusOptions = {}) {
  const shellState = buildAdminShellState(env, initHealth);
  const bootstrap = buildAdminBootstrapPayload(env, initHealth);
  const bootstrapJson = serializeInlineJson(bootstrap);
  const initHealthBannerHtml = buildInitHealthBannerHtml(initHealth);
  const isHealthyShell = initHealth?.ok === true;
  const requestPath = new URL(request.url).pathname;
  const embeddedStatusOptions = {
    ...statusOptions,
    shellState,
    initHealth,
    remoteShellIndexUrl: statusOptions.remoteShellIndexUrl || shellState.remoteShellIndexUrl || "",
    mode: "embedded",
    sourceType: statusOptions.sourceType || "embedded_local",
    routeState: statusOptions.routeState || (isHealthyShell ? "embedded_active" : "embedded_fallback"),
    remoteCacheState: statusOptions.remoteCacheState || (isHealthyShell ? "unused" : "bypassed"),
    lastFetchStatus: statusOptions.lastFetchStatus || (isHealthyShell ? "skipped" : "blocked"),
    reason: statusOptions.reason || (isHealthyShell ? "remote_shell_not_configured" : "init_health_blocked_remote_shell"),
    requestPath
  };
  const appRootHtml = buildEmbeddedAdminFallbackContent(bootstrap, shellState, initHealth, embeddedStatusOptions);
  await patchAdminShellRuntimeStatus(env, embeddedStatusOptions, ctx);

  if (!isHealthyShell) {
    const html = renderAdminHtmlShell(bootstrapJson, initHealthBannerHtml, appRootHtml);
    return new Response(
      request?.method === "HEAD" ? null : html,
      { headers: buildAdminHtmlResponseHeaders("", "no-store, max-age=0") }
    );
  }

  const variantEtag = buildAdminHtmlVariantEtag(bootstrap, initHealth, appRootHtml);
  if (requestHasMatchingEtag(request, variantEtag)) {
    return buildAdminNotModifiedResponse(variantEtag, ADMIN_HTML_CACHE_CONTROL);
  }

  const cacheKey = buildAdminHtmlCacheKeyRequest(request, variantEtag);
  const edgeCache = typeof caches === "undefined" ? null : caches.default;
  if (edgeCache && typeof edgeCache.match === "function") {
    const cachedResponse = await edgeCache.match(cacheKey);
    if (cachedResponse) {
      return request?.method === "HEAD"
        ? buildAdminHeadResponseFrom(cachedResponse)
        : cachedResponse;
    }
  }

  const html = renderAdminHtmlShell(bootstrapJson, initHealthBannerHtml, appRootHtml);
  const headers = buildAdminHtmlResponseHeaders(variantEtag, ADMIN_HTML_CACHE_CONTROL);
  const cacheableResponse = new Response(html, { headers });
  if (edgeCache && typeof edgeCache.put === "function") {
    const cacheWriteTask = withNonCriticalFallback(
      edgeCache.put(cacheKey, cacheableResponse.clone()),
      "admin.shell_cache_write",
      { path: new URL(request.url).pathname, variantEtag },
      null
    );
    if (ctx && typeof ctx.waitUntil === "function") ctx.waitUntil(cacheWriteTask);
    else await cacheWriteTask;
  }
  return request?.method === "HEAD"
    ? buildAdminHeadResponseFrom(cacheableResponse)
    : cacheableResponse;
}

async function renderRemoteAdminPage(request, env, ctx, initHealth = buildInitHealth(env), remoteShellIndexUrl = resolveAdminShellIndexUrl(env)) {
  const edgeCache = typeof caches === "undefined" ? null : caches.default;
  const shellState = buildAdminShellState(env, initHealth);
  const bootstrap = buildAdminBootstrapPayload(env, initHealth);
  const cacheKey = buildAdminRemoteShellCacheKeyRequest(request, remoteShellIndexUrl);
  const requestPath = new URL(request.url).pathname;

  if (edgeCache && typeof edgeCache.match === "function") {
    const cachedResponse = await edgeCache.match(cacheKey);
    if (cachedResponse) {
      const revalidateDue = shouldRevalidateAdminRemoteShell(cachedResponse);
      if (revalidateDue) {
        const revalidateTask = withNonCriticalFallback(
          revalidateAdminRemoteShellCache(
            request,
            edgeCache,
            cacheKey,
            remoteShellIndexUrl,
            bootstrap,
            initHealth,
            cachedResponse.clone()
          ),
          "admin.remote_shell_revalidate",
          { path: requestPath, remoteShellIndexUrl },
          null
        );
        if (ctx && typeof ctx.waitUntil === "function") ctx.waitUntil(revalidateTask);
        else void revalidateTask;
      }
      await patchAdminShellRuntimeStatus(env, {
        shellState,
        initHealth,
        remoteShellIndexUrl,
        mode: "remote",
        sourceType: "remote_cache",
        routeState: "remote_active",
        remoteCacheState: revalidateDue ? "stale_hit" : "hit",
        revalidateDue,
        lastFetchStatus: "cached",
        reason: revalidateDue ? "served_cached_remote_shell_and_scheduled_revalidate" : "served_cached_remote_shell",
        requestPath
      }, ctx);
      if (requestMatchesAdminHtmlResponse(request, cachedResponse)) {
        return buildAdminNotModifiedResponseFrom(cachedResponse, ADMIN_REMOTE_SHELL_BROWSER_CACHE_CONTROL);
      }
      return buildAdminRemoteShellClientResponse(cachedResponse, request?.method);
    }
  }

  const storedResponse = await fetchAdminRemoteShellStoredResponse(remoteShellIndexUrl, bootstrap, initHealth);
  await patchAdminShellRuntimeStatus(env, {
    shellState,
    initHealth,
    remoteShellIndexUrl,
    mode: "remote",
    sourceType: "remote_fetch",
    routeState: "remote_active",
    remoteCacheState: "miss",
    lastFetchStatus: "fetched",
    reason: "fetched_remote_shell_index",
    requestPath
  }, ctx);
  if (edgeCache && typeof edgeCache.put === "function") {
    const cacheWriteTask = withNonCriticalFallback(
      edgeCache.put(cacheKey, storedResponse.clone()),
      "admin.remote_shell_cache_write",
      { path: requestPath, remoteShellIndexUrl },
      null
    );
    if (ctx && typeof ctx.waitUntil === "function") ctx.waitUntil(cacheWriteTask);
    else await cacheWriteTask;
  }

  if (requestMatchesAdminHtmlResponse(request, storedResponse)) {
    return buildAdminNotModifiedResponseFrom(storedResponse, ADMIN_REMOTE_SHELL_BROWSER_CACHE_CONTROL);
  }
  return buildAdminRemoteShellClientResponse(storedResponse, request?.method);
}

async function renderAdminPage(request, env, ctx, initHealth = buildInitHealth(env)) {
  const isHealthyShell = initHealth?.ok === true;
  if (!isHealthyShell) {
    return renderEmbeddedAdminPage(request, env, ctx, initHealth, {
      sourceType: "embedded_local",
      routeState: "embedded_fallback",
      remoteCacheState: "bypassed",
      lastFetchStatus: "blocked",
      reason: "init_health_blocked_remote_shell"
    });
  }

  const remoteShellIndexUrl = resolveAdminShellIndexUrl(env);
  if (remoteShellIndexUrl) {
    try {
      const remoteResponse = await renderRemoteAdminPage(request, env, ctx, initHealth, remoteShellIndexUrl);
      if (remoteResponse) return remoteResponse;
    } catch (error) {
      logRuntimeFailure("admin.remote_shell_render", error, {
        path: new URL(request.url).pathname,
        remoteShellIndexUrl
      });
      return renderEmbeddedAdminPage(request, env, ctx, initHealth, {
        remoteShellIndexUrl,
        sourceType: "embedded_local",
        routeState: "embedded_fallback",
        remoteCacheState: "bypassed",
        lastFetchStatus: "failed",
        reason: `remote_shell_render_failed: ${String(error?.message || error || "unknown_error").trim()}`
      });
    }
  }

  return renderEmbeddedAdminPage(request, env, ctx, initHealth, {
    remoteShellIndexUrl,
    sourceType: "embedded_local",
    routeState: "embedded_active",
    remoteCacheState: "unused",
    lastFetchStatus: "disabled",
    reason: "remote_shell_not_configured"
  });
}

function renderLandingPage(env, initHealth = buildInitHealth(env)) {
  const adminPath = getAdminPath(env);
  const initBanner = initHealth.ok
    ? ''
    : `<div class="landing-banner"><div class="landing-banner-title">系统未初始化</div><div class="landing-banner-text">缺少关键环境变量：${initHealth.missing.map(item => escapeHtml(item)).join('、')}</div></div>`;
  const html = `<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><link rel="icon" href="/favicon.ico" sizes="any"><title>Emby Proxy V19.2</title>${LANDING_PAGE_STYLE_HTML}</head><body><main class="landing-shell"><section class="landing-card"><div class="landing-grid"><div class="landing-primary">${initBanner}<div class="landing-pill">Headless Edge Relay</div><h1 class="landing-title">Emby Proxy V19.2</h1><p class="landing-text">为了极致优化视频代理的性能，当前根路径默认只保留一个无头（Headless）数据中继站；真正的管理界面、节点控制和 DNS 运维都收敛到单独的管理台入口。</p><p class="landing-text landing-text-muted">如果你现在需要配置节点、查看运行状态或调整 Cloudflare 相关参数，请直接访问 <span class="landing-highlight">${escapeHtml(adminPath)}</span>。</p><div class="landing-actions"><a href="${escapeHtml(adminPath)}" class="landing-btn landing-btn-primary">访问 ${escapeHtml(adminPath)}</a><a href="https://github.com/axuitomo/CF-EMBY-PROXY-UI" target="_blank" rel="noopener noreferrer" class="landing-btn landing-btn-secondary">查看项目说明</a></div></div><div class="landing-side"><div class="landing-notes"><div class="landing-notes-title">Routing Notes</div><ul class="landing-note-list"><li>根路径仅提供静态说明页，不承载实时配置数据。</li><li><code>${escapeHtml(adminPath)}</code> 下发 SaaS 控制台骨架，动态数据继续走 <code>POST ${escapeHtml(adminPath)}</code> API。</li><li>媒体代理、日志与 KV / D1 逻辑保持原 Worker 主链路不变。</li></ul></div></div></div></section></main></body></html>`;
  const headers = new Headers({ 'Content-Type': 'text/html;charset=UTF-8', 'Cache-Control': 'public, max-age=3600, s-maxage=86400' });
  applySecurityHeaders(headers);
  headers.set('X-Frame-Options', 'DENY');
  return new Response(html, { headers });
}

function buildRequestPathRedirectResponse(request, targetPath = "/", status = 302) {
  const redirectUrl = new URL(request.url);
  redirectUrl.pathname = sanitizeProxyPath(targetPath || "/");
  redirectUrl.search = "";
  redirectUrl.hash = "";
  const headers = new Headers({ Location: redirectUrl.toString(), "Cache-Control": "no-store, max-age=0" });
  applySecurityHeaders(headers);
  return new Response(null, { status, headers });
}

